import osimport utils_study study = utils_study.Studyutils = utils_study.Utils()import utils_preprocessing_analysispipeline = utils_preprocessing_analysis.OPM_Pipeline(incl_report=False)#%% ----------------------------------------------# =============================================================================# Set up# =============================================================================#Get pathsprojectname = 'project_micropiloting_infants_opm'path_sourcedata, path_processed_data, path_sensorlocations, path_results = utils.get_paths(projectname,'sensor_locations_mp_fixed.csv')ßbasename = '{subj}/{date}_{time}_{sub-subj}_file-{task}_upright_filtered_01_notch_100.fif'dataset = study(os.path.join(path_processed_data, basename)) # Reading fif data# List all folders / subjects in the project directorysubjects = [f for f in os.listdir(path_processed_data) if os.path.isdir(os.path.join(path_processed_data, f))]print(subjects)#%% ----------------------------------------------# Load datasetsdata = pipeline.load_data(dataset, subjects)ica_data = [pipeline.run_ICA(d, projectname, path_results, False) for d in data]# Save fif files with event info[utils.save_fif_path(d, 'ica', path_processed_data) for d in ica_data]